document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("tool-search");if(!e)return;const t=document.querySelectorAll(".tools-grid .tool-card");e.addEventListener("input",function(e){const n=e.target.value.toLowerCase();t.forEach(function(e){const t=e.querySelector(".tool-title").textContent.toLowerCase(),s=e.querySelector(".tool-desc").textContent.toLowerCase(),o=t.includes(n)||s.includes(n);e.style.display=o?"":"none"})})})